import { useState } from "react";

import axios from "axios";

export default function Register() {

  const [form, setForm] = useState({
    role: "customer",
    skills: []
  });

  const jobs = [
    "Electrician",
    "Plumber",
    "Painter",
    "Carpenter",
    "Cleaner",
    "Technician",
    "Welder",
    "Driver",
    "Gardener",
    "Mason"
  ];

  const handleSkillChange = (e) => {

    const selectedOptions =
      Array.from(e.target.selectedOptions)
        .map(option => option.value);

    setForm({
      ...form,
      skills: selectedOptions
    });
  };

  const register = async () => {

    try {

      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        form
      );

      localStorage.setItem(
        "user",
        JSON.stringify(res.data)
      );

      alert("Registration Successful");

      if (form.role === "customer") {

        window.location = "/customer";

      } else {

        window.location = "/labour";
      }

    } catch (err) {

      alert(
        err.response?.data?.message ||
        "Registration Failed"
      );
    }
  };

  return (

    <div style={styles.page}>

      <div style={styles.card}>

        <h1 style={styles.heading}>
          Create Account
        </h1>

        {/* ROLE */}

        <select
          style={styles.input}
          onChange={(e) =>
            setForm({
              ...form,
              role: e.target.value
            })
          }
        >

          <option value="customer">
            Customer
          </option>

          <option value="labour">
            Labour
          </option>

        </select>

        {/* NAME */}

        <input
          style={styles.input}
          placeholder="Full Name"
          onChange={(e) =>
            setForm({
              ...form,
              name: e.target.value
            })
          }
        />

        {/* EMAIL */}

        <input
          style={styles.input}
          placeholder="Email"
          onChange={(e) =>
            setForm({
              ...form,
              email: e.target.value
            })
          }
        />

        {/* PASSWORD */}

        <input
          type="password"
          style={styles.input}
          placeholder="Password"
          onChange={(e) =>
            setForm({
              ...form,
              password: e.target.value
            })
          }
        />

        {/* LABOUR ONLY */}

        {form.role === "labour" && (

          <>

            <label style={styles.label}>
              Select Work Types
            </label>

            <select
              multiple
              style={styles.multiSelect}
              onChange={handleSkillChange}
            >

              {jobs.map((job, index) => (

                <option key={index} value={job}>
                  {job}
                </option>

              ))}

            </select>

            <p style={styles.note}>
              Hold CTRL to select multiple jobs
            </p>

            <input
              style={styles.input}
              placeholder="Base Price"
              onChange={(e) =>
                setForm({
                  ...form,
                  price: e.target.value
                })
              }
            />

          </>
        )}

        {/* BUTTON */}

        <button
          style={styles.btn}
          onClick={register}
        >
          Register
        </button>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    fontFamily: "Arial"
  },

  card: {
    width: "420px",
    background: "white",
    padding: "35px",
    borderRadius: "16px",
    boxShadow: "0 4px 15px rgba(0,0,0,0.06)"
  },

  heading: {
    marginBottom: "25px",
    color: "#111827"
  },

  input: {
    width: "100%",
    padding: "14px",
    marginBottom: "15px",
    borderRadius: "8px",
    border: "1px solid #ddd",
    fontSize: "15px"
  },

  label: {
    display: "block",
    marginBottom: "10px",
    color: "#374151"
  },

  multiSelect: {
    width: "100%",
    height: "140px",
    padding: "10px",
    borderRadius: "8px",
    border: "1px solid #ddd",
    marginBottom: "10px"
  },

  note: {
    fontSize: "13px",
    color: "#6b7280",
    marginBottom: "15px"
  },

  btn: {
    width: "100%",
    padding: "14px",
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "15px"
  }

};
